const now = new Date();

const getNextMonthName = () => new Date(new Date().setMonth(new Date().getMonth() + 1)).toLocaleString('es-ES', { month: 'long' }).replace(/^\w/, c => c.toUpperCase());

let targetMonth = now.getMonth() + 1;
if (targetMonth > 11) {
    targetMonth = 0;
}
const targetMonthName = getNextMonthName();
const results = [];

// ✅ FIX: Parser manual para formato D/MM/YYYY o DD/MM/YYYY
const parseFecha = (fechaString) => {
    if (!fechaString) return null;
    const parts = fechaString.trim().split('/');
    if (parts.length !== 3) return null;
    const day   = parseInt(parts[0], 10);
    const month = parseInt(parts[1], 10) - 1; // 0-11
    const year  = parseInt(parts[2], 10);
    if (isNaN(day) || isNaN(month) || isNaN(year)) return null;
    return { day, month, year }; // trabajamos con partes, sin Date object
};

const calculateDifferenceInYears = (year) => {
    const nextEventYear = now.getFullYear() + (targetMonth > now.getMonth() ? 0 : 1);
    return nextEventYear - year;
};

for (const item of $input.all()) {
    const row = item.json;

    const nameField         = 'name';
    const birthdayDateField = 'birthdayDate';
    const admissionDateField = 'admissionDate';
    const countryField      = 'country';

    const chequearFecha = (fechaString, tipoEvento) => {
        if (!fechaString) return;

        // ✅ Parseo manual, sin new Date()
        const parsed = parseFecha(fechaString);
        if (!parsed) return;

        const { day, month, year } = parsed;

        // ✅ Comparamos el mes directamente (ambos en índice 0-11)
        if (month === targetMonth) {
            const diffAños = calculateDifferenceInYears(year);

            const datePart  = day.toString().padStart(2, '0');
            const monthPart = (month + 1).toString().padStart(2, '0');
            const fechaDisplay = `${datePart}/${monthPart}/${year}`;

            const icono = tipoEvento === 'Cumpleaños' ? '🎂' : '🥇';
            const mensajeCompleto = `${fechaDisplay} | ${diffAños} años`;

            results.push({
                json: {
                    month:               targetMonthName,
                    nombre:              row[nameField],
                    country:             row[countryField] || '',
                    tipo:                tipoEvento,
                    fecha_display:       fechaDisplay,
                    fecha_sort_key:      datePart,
                    edad_o_antiguedad:   diffAños,
                    mensaje_completo:    mensajeCompleto
                }
            });
        }
    };

    chequearFecha(row[birthdayDateField],  'Cumpleaños');
    chequearFecha(row[admissionDateField], 'Aniversario');
}

if (results.length === 0) {
    return [{
        json: {
            mensaje:        "No se encontraron cumpleaños ni aniversarios para el próximo mes.",
            hay_eventos:    false,
            mes_analizado:  targetMonthName
        }
    }];
}

return results;

// Obtenemos todos los items de entrada
const items = $input.all();

// 1. Verificamos si es el mensaje de "No hay eventos"
if (items.length > 0 && items[0].json.hay_eventos === false) {
	const mensajeVacio = `
		<div style="font-family: Arial, sans-serif; color: #555; padding: 20px; text-align: center; border: 1px solid #ddd; border-radius: 8px;">
			<h3>📅 Próximo Mes</h3>
			<p>No hay cumpleaños ni aniversarios registrados para el mes entrante.</p>
		</div>
	`;
	return [{ json: { html_email: mensajeVacio } }];
}

// 2. Si hay datos, los ordenamos por día (para que el email se vea ordenado cronológicamente)
// Extraemos el día de la fecha "2000-12-13" -> 13
items.sort((a, b) => {
	const diaA = parseInt(a.json.fecha_display.split('/')[2]);
	const diaB = parseInt(b.json.fecha_display.split('/')[2]);
	return diaA - diaB;
});

// 3. Construimos las filas de la tabla HTML
let filasHtml = '';

for (const item of items) {
	const empleado = item.json;
	// const dia = empleado.fecha.split('-')[2]; // Ya no se usa solo el día

	// Definimos estilos/iconos según el tipo
	let estiloBadge = '';
	let icono = '';

	if (empleado.tipo === 'Cumpleaños') {
		estiloBadge = 'background-color: #e3f2fd; color: #1565c0; border: 1px solid #bbdefb;'; // Azulito
		icono = '🎂';
	} else {
		estiloBadge = 'background-color: #fff3e0; color: #e65100; border: 1px solid #ffe0b2;'; // Naranja
		icono = '🥇';
	}

	filasHtml += `
		<tr style="border-bottom: 1px solid #eee;">
			<td style="padding: 12px; text-align: center; font-weight: bold; color: #333;">${empleado.mensaje_completo}</td>
			<td style="padding: 12px; color: #333;">${empleado.nombre}</td>
			<td style="padding: 12px; text-align: center; color: #333;">${empleado.country || 'N/A'}</td>
			<td style="padding: 12px; text-align: center;">
				<span style="display: inline-block; padding: 4px 12px; border-radius: 12px; font-size: 12px; font-weight: bold; ${estiloBadge}">
					${icono} ${empleado.tipo}
				</span>
			</td>
		</tr>
	`;
}

// 4. Armamos la estructura completa del HTML
const htmlFinal = `
<div style="font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; max-width: 800px; margin: 0 auto; border: 1px solid #e0e0e0; border-radius: 8px; overflow: hidden;">

	<div style="background-color: #4a90e2; color: white; padding: 20px; text-align: center;">
		<h2 style="margin: 0; font-size: 24px;">🎉 Celebraciones de ${$input.first().json.month}</h2>
		<p style="margin: 5px 0 0 0; opacity: 0.9; font-size: 14px;">Fechas importantes del equipo</p>
	</div>

	<table style="width: 100%; border-collapse: collapse; background-color: white;">
		<thead>
			<tr style="background-color: #f9f9f9; text-transform: uppercase; font-size: 12px; color: #666;">
				<th style="padding: 12px; text-align: center; width: 100px;">Fecha</th>
				<th style="padding: 12px; text-align: left;">Colaborador</th>
				<th style="padding: 12px; text-align: center; width: 100px;">País</th>
				<th style="padding: 12px; text-align: center; width: 120px;">Celebración</th>
			</tr>
		</thead>
		<tbody>
			${filasHtml}
		</tbody>
	</table>

	<div style="background-color: #f5f5f5; padding: 10px; text-align: center; font-size: 11px; color: #888;">
		Reporte generado automáticamente por n8n
	</div>
</div>
`;

// Devolvemos un solo item con el HTML listo para enviar
return [{ json: { html_email: htmlFinal } }];

// 1. Lista de países
const countriesList = ["Argentina", "Colombia", "Perú", "Costa Rica", "Bolivia", "Ecuador", "España"];

// Función para quitar acentos y dejar en minúsculas (Normalización)
const normalize = (text) => {
  return text.normalize("NFD")
             .replace(/[\u0300-\u036f]/g, "")
             .toLowerCase()
             .trim();
};

// 2. Obtener el contenido y limpiar HTML de Teams
let rawContent = items[0].json.body.content.replace(/<[^>]*>/g, "");

// 3. Separar por comas
let parts = rawContent.split(',').map(p => p.trim()).filter(p => p !== "");

let country = "";
let dates = [];
let nameParts = [];

// 4. Procesamiento
for (let part of parts) {
    let normalizedPart = normalize(part);

    // ¿Es un país? Comparamos versiones normalizadas
    let foundCountry = countriesList.find(c => normalize(c) === normalizedPart);

    if (foundCountry) {
        country = foundCountry; // Guardamos el nombre "bonito" (Perú)
        continue;
    }

    // ¿Es una fecha? (dd/mm/yyyy)
    if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(part)) {
        let [day, month, year] = part.split('/');
        dates.push({
            original: part,
            dateObj: new Date(year, month - 1, day)
        });
        continue;
    }

    // Si no es país ni fecha, es el nombre
    nameParts.push(part);
}

// 5. Lógica de fechas
let birthdayDate = "";
let admissionDate = "";

if (dates.length >= 2) {
    dates.sort((a, b) => a.dateObj - b.dateObj);
    birthdayDate = dates[0].original;
    admissionDate = dates[1].original;
} else if (dates.length === 1) {
    admissionDate = dates[0].original;
}

return {
    name: nameParts.join(" "),
    country: country,
    birthdayDate: birthdayDate,
    admissionDate: admissionDate
};
